export type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

export type Customer = {
  yearsWithMHPCO: number;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type ClaimStep = {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: Damage[];
  };
