export type QuoteResult = {
  premium: number;
};

export type ClaimResult = {
  payout: number;
  remainingCap: number;
};

export type ScenarioResult = {
  results: Array<QuoteResult | ClaimResult>;
};

export const processScenario = (_scenario: Scenario): ScenarioResult => {
  return undefined as unknown as ScenarioResult;
};

