describe("MHPCO Claim Office", () => {
  it("should quote a single sword with no modifiers: base premium plus processing fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    // base: 100, first insurance +10% = 110, processing fee +5 = 115
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("should quote a single component with no modifiers: component premium plus processing fee");
  it.todo("should quote 3 alike components at bundle rate plus processing fee");
  it.todo("should apply 50% surcharge for a cursed item");
  it.todo("should apply 20% loyalty discount for long-standing customer (>=2 years)");
  it.todo("should pay out damage minus deductible for a basic claim");
  it.todo("should fully reimburse damage to dragon material items");
  it.todo("should reduce remaining cap after each claim");
});

