const BASE_PREMIUMS: Record<ItemType, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const base = BASE_PREMIUMS[step.items[0].type];
      const premium = Math.ceil(base * 1.10) + 5;
      return { premium };
    }
    return {} as ClaimResult;
  });
  return { results };
};

