  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isBundle = step.items.length === 3 && step.items.every((i) => i.type === "component");
      const base = isBundle ? 60 : BASE_PREMIUMS[step.items[0].type];
      const premium = Math.ceil(base * 110 / 100) + PROCESSING_FEE;
      return { premium };
    }
    return {} as ClaimResult;
  });
  return { results };
};

