      const base = isBundle ? 60 : BASE_PREMIUMS[step.items[0].type];
      const cursedSurcharge = step.items[0].cursed ? CURSED_SURCHARGE_PERCENT : 0;
      const ratePercent = 110 + cursedSurcharge;
      const premium = Math.ceil(base * ratePercent / 100) + PROCESSING_FEE;
      return { premium };
    }
    return {} as ClaimResult;
  });
  return { results };
};

