it("should fully reimburse damage to dragon material items", () => {
  const result = processScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword", material: "dragon", enchantment: 2, cursed: false }],
